/**
 * @return the squared distance between the given points
 */
public static float dst2(final float x1, final float y1, final float z1, final float x2, final float y2, final float z2) {
    final float a = x2 - x1;
    final float b = y2 - y1;
    final float c = z2 - z1;
    return a * a + b * b + c * c;
}
